{"cmd":"cd /app && python -c "
import json, pandas as pd

with open('/data/source_a/users.json', 'r') as f:
    source_a_raw = json.load(f)
source_b_raw = pd.read_csv('/data/source_b/users.csv').to_dict(orient='records')
source_c_raw = pd.read_parquet('/data/source_c/users.parquet').to_dict(orient='records')

def map_source_a(record):
    return {'user_id': int(record['id']), 'name': record['full_name'], 'email': record['email'], 'created_date': record['registration_date'], 'status': record.get('status', None)}

def map_source_b(record):
    return {'user_id': int(record['user_id']), 'name': record['name'], 'email': record['email_address'], 'created_date': record['created_at'], 'status': str(record.get('is_active', ''))}

def map_source_c(record):
    return {'user_id': int(record['userId']), 'name': record['userName'], 'email': record['email'], 'created_date': record['joined'], 'status': str(record.get('active', ''))}

source_a = [map_source_a(r) for r in source_a_raw]
source_b = [map_source_b(r) for r in source_b_raw]
source_c = [map_source_c(r) for r in source_c_raw]

print('Source A:', source_a)
print('Source B:', source_b)
print('Source C:', source_c)
"
"}

